 11	
 12	/// <summary>
 13	/// Represents a filter attribute that confirms access to functional
 14	/// </summary>
 15	[AttributeUsage(AttributeTargets.Method, AllowMultiple = true)]
 16	public sealed class CheckPermissionAttribute : TypeFilterAttribute
 17	{
 18	    #region Ctor
 19	
 20	    /// <summary>
 21	    /// Create instance of the filter attribute
 22	    /// </summary>
 23	    /// <param name="permissionSystemName">Permission to check</param>
 24	    /// <param name="resultType">The result type for not confirmed access situation</param>
 25	    public CheckPermissionAttribute(string permissionSystemName, CheckPermissionResultType resultType = CheckPermissionResultType.Default) : base(typeof(CheckPermissionFilter))
 26	    {
 27	        Arguments = new object[] { resultType, new List<string> { permissionSystemName } };
 28	        PermissionSystemName.Add(permissionSystemName);
 29	        ResultType = resultType;
 30	    }
 31	
 32	    /// <summary>
 33	    /// Create instance of the filter attribute
 34	    /// </summary>
 35	    /// <param name="permissionSystemNames">Permissions to check</param>
 36	    /// <param name="resultType">The result type for not confirmed access situation</param>
 37	    public CheckPermissionAttribute(string[] permissionSystemNames, CheckPermissionResultType resultType = CheckPermissionResultType.Default) : base(typeof(CheckPermissionFilter))
 38	    {
 39	        Arguments = new object[] { resultType, permissionSystemNames.ToList() };
 40	        PermissionSystemName.AddRange(permissionSystemNames);
 41	        ResultType = resultType;
 42	    }
 43	
 44	    #endregion
 45	
 46	    #region Properties
 47	
 48	    /// <summary>
 49	    /// Gets a permission system name to check
 50	    /// </summary>
 51	    public List<string> PermissionSystemName { get; } = new();
 52	
 53	    /// <summary>
 54	    /// Gets a check permission result type
 55	    /// </summary>
 56	    public CheckPermissionResultType ResultType { get; }
 57	
 58	    #endregion
 59	
 60	    #region Nested filter
 61	
 62	    /// <summary>
 63	    /// Represents a filter that confirms access
 64	    /// </summary>
 65	    private class CheckPermissionFilter : IAsyncAuthorizationFilter
 66	    {
 67	        #region Fields
 68	
 69	        protected readonly IHttpContextAccessor _httpContextAccessor;
 70	        protected readonly ILocalizationService _localizationService;
 71	        protected readonly IPermissionService _permissionService;
 72	        protected readonly IWebHelper _webHelper;
 73	
 74	        protected readonly CheckPermissionResultType _resultType;
 75	        protected readonly List<string> _permissionSystemNames;
 76	
 77	        #endregion
 78	
 79	        #region Ctor
 80	
 81	        public CheckPermissionFilter(CheckPermissionResultType resultType,
 82	            List<string> permissionSystemNames,
 83	            IHttpContextAccessor httpContextAccessor,
 84	            ILocalizationService localizationService,
 85	            IPermissionService permissionService,
 86	            IWebHelper webHelper)
 87	        {
 88	            _resultType = resultType;
 89	            _permissionSystemNames = permissionSystemNames;
 90	
 91	            _httpContextAccessor = httpContextAccessor;
 92	            _localizationService = localizationService;
 93	            _permissionService = permissionService;
 94	            _webHelper = webHelper;
 95	        }
 96	
 97	        #endregion
 98	
 99	        #region Utilities
100	
101	        /// <summary>
102	        /// Called early in the filter pipeline to confirm request is authorized
103	        /// </summary>
104	        /// <param name="context">Authorization filter context</param>
105	        /// <returns>A task that represents the asynchronous operation</returns>
106	        private async Task AuthorizeAsync(AuthorizationFilterContext context)
107	        {
108	            ArgumentNullException.ThrowIfNull(context);
109	
110	            if (!DataSettingsManager.IsDatabaseInstalled())
111	                return;
112	
113	            if (!context.Filters.Any(filter => filter is CheckPermissionFilter))
114	                return;
115	
116	            //authorize permission
117	            foreach (var permissionSystemName in _permissionSystemNames)
118	            {
119	                if (await _permissionService.AuthorizeAsync(permissionSystemName))
120	                    return;
121	            }
122	
123	            var resultType = _resultType;
124	
125	            var request = _httpContextAccessor.HttpContext?.Request;
126	
127	            if (request == null)
128	                return;
129	
130	            if (resultType == CheckPermissionResultType.Default)
131	            {
132	                resultType = request.Method switch
133	                {
134	                    WebRequestMethods.Http.Post => _webHelper.IsAjaxRequest(request) ? CheckPermissionResultType.Json : CheckPermissionResultType.Html,
135	                    WebRequestMethods.Http.Get => CheckPermissionResultType.Html,
136	                    _ => CheckPermissionResultType.Text,
137	                };
138	            }
139	
140	            IActionResult html()
141	            {
142	                var controller = request.RouteValues.ContainsKey("controller")
143	                    ? request.RouteValues["controller"]
144	                    : string.Empty;
145	
146	                var action = request.RouteValues.ContainsKey("action")
147	                    ? request.RouteValues["action"]
148	                    : string.Empty;
149	
150	                var pageSystemNameKey = $"{controller}.{action}";
151	
152	                return new RedirectToActionResult("AccessDenied", "Security",
153	                    new { pageUrl = _webHelper.GetRawUrl(request), pageSystemNameKey });
154	            }
155	
156	            context.Result = resultType switch
157	            {
158	                CheckPermissionResultType.Json => new JsonResult(new
159	                {
160	                    error = await _localizationService.GetResourceAsync("Admin.AccessDenied.Description")
161	                }),
162	                CheckPermissionResultType.Html => html(),
163	                CheckPermissionResultType.Text => new ContentResult
164	                {
165	                    Content = await _localizationService.GetResourceAsync("Admin.AccessDenied.Description"),
166	                    ContentType = "text/plain",
167	                },
168	                _ => context.Result
169	            };
170	        }
171	
172	        #endregion
173	
174	        #region Methods
175	
176	        /// <summary>
177	        /// Called early in the filter pipeline to confirm request is authorized
178	        /// </summary>
179	        /// <param name="context">Authorization filter context</param>
180	        /// <returns>A task that represents the asynchronous operation</returns>
181	        public async Task OnAuthorizationAsync(AuthorizationFilterContext context)
182	        {
183	            await AuthorizeAsync(context);
184	        }
185	
186	        #endregion
187	    }
188	
189	    #endregion
190	
191	    #region Nested class
192	
193	    public enum CheckPermissionResultType
194	    {
195	        /// <summary>
196	        /// For Get requests it will be <see cref="Html"/>. For POST request it will be <see cref="Json"/> if request is Ajax, <see cref="Html"/> in other case. For other one it will by <see cref="Text"/>
197	        /// </summary>
198	        Default = 0,
199	
200	        /// <summary>
201	        /// Redirect to Access Denied page
202	        /// </summary>
203	        Html = 1,
204	
205	        /// <summary>
206	        /// Return the plain text content
207	        /// </summary>
208	        Text = 2,
209	
210	        /// <summary>
211	        /// Return the JSON content
212	        /// </summary>
213	        Json = 3
214	    }
215	
216	    #endregion
217	}

 55	    /// <summary>
