116	                m.CustomerRoleId == permissionRecordCustomerRoleMapping.CustomerRoleId &&
117	                m.PermissionRecordId == permissionRecordCustomerRoleMapping.PermissionRecordId);
118	
119	            if (mapping != null)
120	            {
121	                permissionRecordCustomerRoleMapping.Id = mapping.Id;
122	
123	                return;
124	            }
125	
126	            await _permissionRecordCustomerRoleMappingRepository.InsertAsync(permissionRecordCustomerRoleMapping, false);
127	            exists.Add(permissionRecordCustomerRoleMapping);
128	        }
129	
130	        foreach (var config in configs)
131	        {
132	            //new permission (install it)
133	            var permission = new PermissionRecord
134	            {
135	                Name = config.Name,
136	                SystemName = config.SystemName,
137	                Category = config.Category
138	            };
139	
140	            //save new permission
141	            await _permissionRecordRepository.InsertAsync(permission);
142	
143	            foreach (var systemRoleName in config.DefaultCustomerRoles)
144	            {
145	                var customerRole = await _customerService.GetCustomerRoleBySystemNameAsync(systemRoleName);
146	
147	                if (customerRole == null)
148	                {
149	                    //new role (save it)
150	                    customerRole = new CustomerRole
151	                    {
152	                        Name = systemRoleName,
153	                        Active = true,
154	                        SystemName = systemRoleName
155	                    };
156	
157	                    await _customerRoleRepository.InsertAsync(customerRole);
158	                }
159	
160	                await addPermissionRecordCustomerRoleMappingIfNotExists(new PermissionRecordCustomerRoleMapping { CustomerRoleId = customerRole.Id, PermissionRecordId = permission.Id });
161	            }
162	
163	            //save localization
164	            await _localizationService.SaveLocalizedPermissionNameAsync(permission);
165	        }
